"""
MKT Original Commentary — 1 Chronicles chapters 11–12
Run: python3 scripts/zc-original-1chronicles-11-12.py

Key translation decisions:
- Ch 11: 'bone and flesh' (v1) = covenant kinship formula (Gen 2:23; 2 Sam 5:1)
- v10: gibbōrîm = warriors/mighty men; rāʾšê = chiefs/commanders
- v11: 'chief of the thirty' — LXX and some MSS read 'three' (šālōš vs šᵉlōšîm)
- v18: ḥālîlāh lî = 'God forbid me' — profanation formula
- v19: bᵉnapšôtām = 'with/at risk of their lives/souls'
- Ch 12: rûaḥ lāḇᵉšāh ʾet-ʿamaśay (v18) = 'the Spirit clothed Amasai'
- v32: yôḏᵉʿê bîn laʿittîm = 'those who understood the times'
- v38: lēḇāḇ šālēm = 'whole heart / undivided heart'
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON1 = {
  "11": {
    "1": "<p><strong>ʿaṣmᵉḵā ûḇāśārᵉḵā</strong> (&lsquo;your bone and your flesh&rsquo;) is the OT&rsquo;s covenant-kinship formula (Gen 2:23 Adam of Eve; Judg 9:2; 2 Sam 5:1). The elders appeal to shared descent to legitimate David&rsquo;s kingship over all Israel after Saul&rsquo;s collapse — the same formula the parallel passage (2 Sam 5:1) uses. Chronicles omits all of David&rsquo;s Hebron years and Ishbosheth&rsquo;s rival reign, moving immediately to this moment of national unity.</p>",
    "2": "<p><strong>ʾattāh hûʾ hammôṣîʾ wᵉhammēḇîʾ</strong> (&lsquo;you were the one who led out and brought in Israel&rsquo;) — military idiom for commanding an army (Num 27:17; 1 Sam 18:13). The elders recall David&rsquo;s past military leadership under Saul as grounds for accepting him as king — he was the real commander all along.</p>",
    "3": "<p><strong>wayyikrōt dāwid lāhem bᵉrît biḥeḇrôn lipnê YHWH</strong> — David cuts a covenant with the elders &lsquo;before the LORD&rsquo; at Hebron. The Davidic kingship is established as a covenant act witnessed by YHWH, not merely a political agreement. <strong>kᵉḏiḇar YHWH bᵉyaḏ šᵉmûʾēl</strong> — &lsquo;according to the word of YHWH by the hand of Samuel&rsquo; — Chronicles frames the event as prophetic fulfillment from the start.</p>",
    "4": "<p><strong>yᵉrûšālaim hiʾ yᵉḇûs</strong> — &lsquo;Jerusalem, that is Jebus&rsquo; — Chronicles identifies Jerusalem by its pre-conquest name (Judges 19:10-11). The Jebusites had held the city since the conquest. The Chronicler begins David&rsquo;s reign with the capture of YHWH&rsquo;s eventual throne city.</p>",
    "5": "<p><strong>lōʾ tāḇôʾ hēnnāh</strong> — &lsquo;you shall not come in here&rsquo; — the Jebusites&rsquo; taunt; in 2 Sam 5:6 they add &lsquo;even the blind and the lame will ward you off&rsquo;. Chronicles omits the taunt content and focuses on the outcome: <strong>wayyilkaḏ dāwid ʾet maṣṣaḏat ṣiyyôn</strong> — &lsquo;David captured the stronghold of Zion&rsquo; — establishing the theological center of the Davidic kingdom.</p>",
    "6": "<p>The appointment formula: <strong>kol makkēh yᵉḇûsî bārîʾšônāh yihyeh lᵉrōʾš wᵉlᵉśār</strong> — &lsquo;whoever strikes the Jebusites first shall become head and commander.&rsquo; This is a meritocratic military appointment. Joab (<em>ben-ṣᵉrûyāh</em> — always identified by his mother, suggesting known status) wins the position. The parallel in 2 Sam 5:8 is obscure; Chronicles&rsquo; version is clearer about the merit-based appointment.</p>",
    "7": "<p><strong>miṣṣaḏāh dāwid</strong> — &lsquo;from the stronghold, David [dwelt]&rsquo; — the fortress that had been Jebus becomes the &lsquo;City of David.&rsquo; The renaming establishes the theological and dynastic identity of Jerusalem. The Chronicler uses this transition as the foundation of the temple-building narrative that dominates chs. 22–29.</p>",
    "8": "<p>Joab is credited with repairing <strong>sheʾār hāʿîr</strong> (&lsquo;the rest of the city&rsquo;) while David builds from the Millo inward. <strong>hammillōʾ</strong> is likely a terraced fill structure supporting the city expansion (cf. 2 Sam 5:9). The collaboration of king and general in urban construction shows the Chronicler&rsquo;s interest in organized communal building — anticipating the temple project.</p>",
    "9": "<p><strong>wayyēlek dāwid hālôḵ wᵉḡāḏôl wᵉYHWH ṣᵉḇāʾôt ʿimmô</strong> — &lsquo;David kept going and growing, and the LORD of hosts was with him.&rsquo; The divine-warrior formula (<em>YHWH ṣᵉḇāʾôt</em> = LORD of armies) grounds David&rsquo;s expansion not in military genius but in divine presence. This is the Chronicler&rsquo;s theological explanation for all Davidic success.</p>",
    "10": "<p><strong>rāʾšê haggibborîm</strong> — &lsquo;chiefs of the mighty men&rsquo; — introduces the famous warrior roster. <strong>ʾăšer ḥizzᵉqû-ʿimmô ḇamlûḵātô</strong> — &lsquo;who strengthened themselves with him in his kingship&rsquo; — the Chronicler frames the Mighty Men as co-participants in establishing the Davidic kingdom, consistent with his overall emphasis on unified all-Israel support for David.</p>",
    "11": "<p><strong>jashobeam ben-ḥakmonî</strong> — head of the three (or thirty, depending on text). The phrase <strong>rōʾš haššālišîm</strong> is disputed: &lsquo;chief of the thirty&rsquo; (MT <em>šᵉlōšîm</em>) vs &lsquo;chief of the three&rsquo; (LXX and some MSS <em>šᵉlōšāh</em>); the parallel in 2 Sam 23:8 has &lsquo;Josheb-basshebeth&rsquo; a different name for possibly the same person. His feat: slaying 300 with a single spear-thrust. The number is symbolic of overwhelming martial prowess.</p>",
    "12": "<p><strong>ʾeleʿāzār ben-dôdô haʾăḥōḥî</strong> — Eleazar son of Dodo the Ahohite, &lsquo;one of the three mighty men.&rsquo; His story follows in v. 13-14. The Ahohites were a Benjaminite sub-clan (8:4). These three men are <em>haggibborîm</em> at the highest tier — an elite within the elite.</p>",
    "13": "<p>The battle at Pas-dammim (here; 2 Sam 23:11 has Lehi) where the Israelites fled from the Philistines over a barley field. The geographical difference between the parallel accounts may reflect different battle sites or text corruption. <strong>wayyāqōmû bᵉtôḵ haḥelqāh wayyaṣṣîlûhā</strong> — &lsquo;they took their stand in the middle of the field and saved it&rsquo; — collective action; v. 14 shows it was Eleazar specifically.</p>",
    "14": "<p><strong>wayyaṣṣîlem YHWH tᵉšûʿāh gᵉḏôlāh</strong> — &lsquo;and YHWH saved [them] with a great salvation.&rsquo; The military victory is attributed entirely to YHWH. <em>tᵉšûʿāh</em> (salvation/deliverance) is the same word-root as <em>yēšûaʿ</em> (Joshua/Jesus). This divine-salvation formula in battle contexts establishes the theological register of all Davidic warfare.</p>",
    "15": "<p>Three of the Thirty go to David at the cave of Adullam while the Philistines are encamped in the valley of Rephaim. The rock (<em>haṣṣûr</em>) is identified with Adullam. The detail that <strong>maṣṣaḇ pᵉlištîm bᵉḇêt leḥem</strong> — &lsquo;the Philistine garrison was at Bethlehem&rsquo; — marks how completely the enemy had occupied David&rsquo;s home territory, heightening the poignancy of his longing.</p>",
    "16": "<p>David is &lsquo;in the stronghold&rsquo; (<em>bammᵉṣûḏāh</em>) while Philistine <em>neṣîḇ</em> (garrison/prefect) holds Bethlehem. The contrast between the cave-king and the occupied homeland generates the narrative tension that leads to David&rsquo;s thirst and its extraordinary fulfillment.</p>",
    "17": "<p><strong>mî yašqēnî mayim mibôr bêt-leḥem</strong> — &lsquo;Who will give me water to drink from the well of Bethlehem at the gate?&rsquo; This is an offhand expression of longing, not a command — which makes the three warriors&rsquo; response more extraordinary. The well at the gate was a civic landmark; the gate = the place of legal assembly and public life.</p>",
    "18": "<p>The three break through the Philistine garrison, draw water from Bethlehem&rsquo;s well, and bring it to David. David&rsquo;s response: <strong>wayyissᵉḵēhû lAYHWH</strong> — &lsquo;he poured it out to YHWH.&rsquo; This is a libation — treating the water as too holy to drink because it was obtained at the risk of blood. The act transforms water into a sacred offering, converting an act of loyalty into an act of worship.</p>",
    "19": "<p><strong>ḥālîlāh lî mēʾĕlōhay</strong> — &lsquo;God forbid it of me / my God, may I not do this.&rsquo; <em>ḥālîlāh</em> is a strong profanation-avowal formula (Gen 44:7; Josh 22:29; 1 Sam 12:23). <strong>hᵉdām hāʾănāšîm hāʾēlleh bᵉnapšôtām</strong> — &lsquo;the blood of these men at the cost of their lives (<em>napšôtām</em>).&rsquo; David refuses to consume what was purchased at the risk of life — a profound meditation on value, sacrifice, and the sacred cost of devotion.</p>",
    "20": "<p><strong>ʾăḇîšay ʾăḥî yôʾāḇ</strong> — Abishai brother of Joab. He &lsquo;lifted up his spear against three hundred and killed them.&rsquo; He is among <em>haššᵉlōšāh</em> (the three) but his status is complex: v. 21 says he was &lsquo;more honored than the two&rsquo; (than Eleazar and Jashobeam? or the other two of the second set of three?). The text is difficult; the Chronicler seems to distinguish two tiers of three.</p>",
    "21": "<p><strong>min-haššᵉlōšāh nikkāḇāḏ</strong> — &lsquo;more honored than the three&rsquo; — but Abishai &lsquo;did not attain to the first three&rsquo; (<em>wᵉʾel-haššᵉlōšāh lōʾ-bāʾ</em>). He was <strong>śar</strong> (officer/captain) of the three. The hierarchical ranking within the Mighty Men reflects a formal military structure.</p>",
    "22": "<p><strong>bᵉnāyāhû ben-yᵉhôyāḏāʿ ben-ʾîš-ḥayil</strong> — &lsquo;Benaiah son of Jehoiada, son of a valiant man.&rsquo; His three exploits: (1) slaying two <em>ʾărîʾēl</em> of Moab (lion-like men or &lsquo;altar-hearths&rsquo; of Moab — meaning debated); (2) slaying a lion in a pit on a snowy day (<em>bᵉyôm haššāleg</em>); (3) slaying a large Egyptian (v. 23). These are listed in ascending difficulty.</p>",
    "23": "<p>Benaiah kills an Egyptian &lsquo;a man of measure&rsquo; (<em>ʾîš middāh</em> — very tall, same formula as Goliath, 1 Chr 20:6) with the Egyptian&rsquo;s own spear. <strong>wayyigzōl ʾet haḥănît miyyaḏ hammiṣrî wayyahaṣṣᵉhû baḥănîtô</strong> — &lsquo;he wrested the spear from the Egyptian&rsquo;s hand and killed him with his own spear.&rsquo; The reversal motif (turning an enemy&rsquo;s weapon against him) appears also in David vs. Goliath and has symbolic resonance: the victor uses the enemy&rsquo;s own power for his destruction. [Existing entry preserved]</p>",
    "24": "<p><strong>ʾēlleh ʿāśāh bᵉnāyāhû</strong> — &lsquo;these things Benaiah did&rsquo; — formal summary of v. 22-23. <strong>wayyᵉhî-lô šēm bᵉšᵉlōšāh haggibborîm</strong> — &lsquo;he had a name among the thirty mighty men&rsquo; (MT &lsquo;three&rsquo; — text uncertain as at v. 11). His fame is specifically named, not just assumed.</p>",
    "25": "<p>Benaiah &lsquo;was honored beyond the thirty&rsquo; (<em>nikkāḇāḏ hûʾ min-haššᵉlōšîm</em>) but did not attain to the Three. David set him over his bodyguard (<em>mišmaʿtô</em>). This administrative note shows the Chronicler&rsquo;s interest in the organization of David&rsquo;s court — which directly relates to his preparations for temple governance.</p>",
    "26": "<p>The roster of &lsquo;valiant men of the armies&rsquo; (<em>gibbôrê haḥăyālîm</em>) begins. These are the Thirty (roughly) — a second tier below the Three. <strong>ʾăśāhʾēl ʾăḥî yôʾāḇ</strong> — Asahel brother of Joab, who famously died in 2 Sam 2 pursuing Abner. His inclusion here, alongside Elhanan of Bethlehem, begins a list that will end with Uriah the Hittite (v. 41).</p>",
    "27": "<p>Shammoth the Harorite and Helez the Pelonite — geographical epithets identify their tribal origins. The parallel in 2 Sam 23:25-26 has slightly variant names (Shammah the Harodite / Helez the Paltite). The differences likely reflect copyist variants in proper names, a common phenomenon in these lists.</p>",
    "28": "<p>Ira son of Ikkesh the Tekoite and Abiezer the Anathothite. Anathoth is the priestly town later famous as Jeremiah&rsquo;s birthplace (Jer 1:1). The warrior list crosses geographic lines — Tekoa, Anathoth, and many other towns — showing David&rsquo;s coalition of all-Israel support.</p>",
    "29": "<p>Sibbecai the Hushathite — who will appear in ch. 20:4 killing Sippai the giant. Ilai the Ahohite. The Hushathites are a Judahite sub-group (1 Chr 4:4). The recurrence of Ahohite warriors (cf. v. 12) suggests a clan with a strong martial tradition.</p>",
    "30": "<p>Maharai the Netophathite and Heled son of Baanah the Netophathite. Netophah is near Bethlehem (Ezra 2:22); the two Netophathites together suggest geographic clustering within the list.</p>",
    "31": "<p>Ithai son of Ribai of Gibeah — Gibeah is Saul&rsquo;s hometown (1 Sam 10:26), so this Benjaminite warrior serves David even from the house of Saul&rsquo;s city. Benaiah the Pirathonite (Ephraim, Judg 12:15). The list&rsquo;s geographic breadth — from Gibeah to Pirathon — reflects all-Israel participation.</p>",
    "32": "<p>Hurai of the brooks of Gaash and Abiel the Arbathite. &lsquo;Brooks of Gaash&rsquo; references the area where Joshua was buried (Josh 24:30). The Arbathite is from Beth-arabah (Josh 15:6), near the Dead Sea rift.</p>",
    "33": "<p>Azmaveth the Baharumite (2 Sam 23:31 has &lsquo;Barhumite&rsquo; — likely variant of the same place, Bahurim, 2 Sam 3:16) and Eliahba the Shaalbonite (from Shaalabbin, Dan&rsquo;s territory, Josh 19:42). Both names appear only in the Mighty Men lists.</p>",
    "34": "<p>Jonathan son of Shage the Hararite and &lsquo;the sons of Hashem the Gizonite&rsquo; — Gizon is otherwise unattested in the OT; possibly a scribal corruption. The Hararites appear several times in the list (vv. 34-35), suggesting a warrior clan from the hill country.</p>",
    "35": "<p>Ahiam son of Sacar the Hararite and Eliphal son of Ur. The 2 Sam 23:33 parallel has &lsquo;Ahiam son of Sharar the Hararite&rsquo; — the variant between Sacar and Sharar is a typical copyist confusion of <em>kāp̄</em> and <em>rēš</em>. These variants are numerous throughout the parallel lists and generally have no theological significance.</p>",
    "36": "<p>Hepher the Mecherathite (unattested elsewhere) and Ahijah the Pelonite. The Pelonite appears again at v. 27 (Helez). The frequent &lsquo;-ite&rsquo; demonymic forms indicate these warriors are identified by their home towns or clans, not by patronymics — suggesting some are from small or obscure communities.</p>",
    "37": "<p>Hezro the Carmelite (from Carmel in Judah, 1 Sam 25:2, Nabal&rsquo;s home) and Naarai son of Ezbai. The Carmelite connection links to Abigail&rsquo;s homeland. These warriors are from the Judean heartland.</p>",
    "38": "<p>Joel brother of Nathan — if Nathan here is David&rsquo;s prophet, this would link a warrior directly to a royal courtier. More likely a different Nathan. Mibhar son of Hagri (2 Sam 23:36 reads differently — possibly scribal). The Hagrites were a trans-Jordanian people (1 Chr 5:10); a Hagrite&rsquo;s son among David&rsquo;s elite shows the ethnically inclusive character of the warrior band.</p>",
    "39": "<p>Zelek the Ammonite — an Ammonite among David&rsquo;s elite warriors. Naharai the Berothite, armor-bearer of Joab son of Zeruiah. The presence of an Ammonite (enemy nation) and a servant of Joab in the Thirty reflects the diverse and personally loyal character of David&rsquo;s military family.</p>",
    "40": "<p>Ira the Ithrite and Gareb the Ithrite — two warriors from the same clan appearing together. The Ithrites were a Judahite sub-group (2 Sam 23:38).</p>",
    "41": "<p><strong>ʾûriyyāh haḥittî</strong> — Uriah the Hittite appears at the very end of the elite warrior roster. In 2 Sam 23:39, he is the thirty-seventh and last named. This placement is almost certainly intentional in the literary ordering — Uriah the Hittite, the most loyal of all the Mighty Men, the one David had murdered. The Chronicler reproduces the list including Uriah; he omits the Bathsheba narrative (as he omits David&rsquo;s failures generally) but includes Uriah&rsquo;s name in the honor roll.</p>",
    "42": "<p>Adina son of Shiza the Reubenite, chief of the Reubenites, and thirty with him. The Reubenite contingent has its own sub-commander. This entry marks the transition to a broader military survey that extends beyond the original core group.</p>",
    "43": "<p>Hanan son of Maacah and Joshaphat the Mithnite. Maacah is a place-name (Aram-maacah, north of Dan) as well as a personal name. These names appear only here.</p>",
    "44": "<p>Uzzia the Ashterathite (from Ashtaroth in Bashan, trans-Jordan — Manassite territory), Shama and Jeiel sons of Hothan the Aroerite (Aroer, different from Gad&rsquo;s Aroer — possibly the Judean Aroer of 1 Sam 30:28).</p>",
    "45": "<p>Jediael son of Shimri and Joha his brother the Tizite. &lsquo;Tizite&rsquo; is unattested elsewhere; possibly a corrupt form of another place-name.</p>",
    "46": "<p>Eliel the Mahavite; sons of Elnaam: Jeribai and Joshaviah; Ithmah the Moabite. Another Moabite (cf. Zelek the Ammonite, v. 39) in David&rsquo;s corps — showing the expanding ethnic scope of the Davidic coalition. The Mahavite clan is otherwise unknown.</p>",
    "47": "<p>Eliel, Obed, and Jaasiel the Mesobaite conclude the list. &lsquo;Mesobaite&rsquo; is unattested; possibly a place-name. The list of Mighty Men (vv. 26-47) totals approximately thirty-seven names, though some are grouped. The Chronicler uses this list to show all-Israel participation in David&rsquo;s kingdom from the start — consistent with his broader theological agenda.</p>"
  },
  "12": {
    "1": "<p><strong>wᵉʾēlleh habbāʾîm ʾel-dāwid bᵉṣiqlag</strong> — &lsquo;and these are those who came to David at Ziklag.&rsquo; Ziklag was the Philistine city given to David during his exile (1 Sam 27:6). <strong>bᵉʿôḏ ʿāṣûr mippᵉnê šāʾûl ben-qîš</strong> — &lsquo;while still restrained from before Saul son of Kish&rsquo; — the fugitive period. The Chronicler includes this section to show that David&rsquo;s all-Israel coalition began forming before he was king, predating any political opportunity.</p>",
    "2": "<p><strong>middōšᵉqê qešet</strong> — &lsquo;armed with the bow, right-handed and left-handed in hurling stones.&rsquo; The Benjaminite warriors&rsquo; ambidexterity is a military specialty noted also in Judg 20:16 (the men of Gibeah who could sling a stone to a hair&rsquo;s breadth). Their joining David from Saul&rsquo;s own tribe is particularly significant — Benjamin loyalty shifting from Saul to David.</p>",
    "3": "<p>The list of Benjaminite warriors begins with Ahiezer and Joash sons of Shemaah the Gibeathite. Gibeah, again, is Saul&rsquo;s city. These Benjaminites from Saul&rsquo;s hometown came to David, the ultimate statement of cross-tribal loyalty. Jeziel and Pelet sons of Azmaveth — Azmaveth also appears in the Mighty Men list (11:33).</p>",
    "4": "<p>Ishmaiah the Gibeonite is noted as &lsquo;mighty among the Thirty and over the Thirty&rsquo; — i.e., ranking within the elite corps already established. Jeremiah, Jahaziel, Johanan, and Josabad the Gederathite fill out the contingent. The overlapping names with the Mighty Men list suggest the two lists derive from the same military administrative source.</p>",
    "5": "<p>Eluzai, Jerimoth, Bealiah, Shemariah, and Shephatiah the Haruphite. The Haruph clan is mentioned in Nehemiah 7:24 as returnees from exile — linking these pre-exile warriors to the post-exile community the Chronicler is addressing.</p>",
    "6": "<p>Elkanah, Isshiah, Azarel, Joezer, and Jashobeam the Korahites. The Korahites were a Levitical guild associated with temple music and gatekeeping (1 Chr 6:22; 9:19). Their appearance in a warrior list suggests the boundary between cultic and military roles was permeable in the early monarchy.</p>",
    "7": "<p>Joelah and Zebadiah sons of Jeroham from Gedor. Gedor is a Judahite town (4:4) — a further note of Judahite support for David supplementing the Benjaminite contingent.</p>",
    "8": "<p><strong>ûmin-haggāḏî niphrᵉḏû ʾel-dāwid lamlᵉḏbārāh</strong> — &lsquo;from the Gadites there separated themselves to David in the wilderness.&rsquo; The desert/wilderness period references David&rsquo;s time in the Judean wilderness (1 Sam 22-26). These Gadites, from trans-Jordan, crossed to join the fugitive king. <strong>gibborê ḥayil anšê ṣāḇāʾ lamilḥāmāh maʿarᵉḵê ṣinnāh warōmaḥ</strong> — &lsquo;valiant men, warriors for war, trained to handle shield and spear.&rsquo; <strong>ûp̄ᵉnêhem pᵉnê ʾaryēh</strong> — &lsquo;their faces were like the faces of lions&rsquo; — the lion-face simile for fierce warriors.</p>",
    "9": "<p>The Gadite commanders are listed in order: Ezer the first, Obadiah the second, Eliab the third. The ordinal numbering (<em>hārîʾšônāh, haššᵉnî, haššᵉlîšî</em>, etc.) continues through v. 13, imposing a clear hierarchical structure. This military ranking system shows sophisticated administrative organization during David&rsquo;s fugitive period.</p>",
    "10": "<p>Mishmannah the fourth, Jeremiah the fifth — the list continues. The Gadite names recur in the trans-Jordanian genealogies of ch. 5. The Chronicler links these warriors back to their tribal genealogies, showing the all-Israel framework of the David narrative.</p>",
    "11": "<p>Attai the sixth, Eliel the seventh. The name Eliel appears multiple times in these lists (11:46-47; 12:11) — likely different individuals sharing a common theophoric name (&lsquo;my God is God&rsquo;).</p>",
    "12": "<p>Johanan the eighth, Elzabad the ninth. The list of Gadite officers reaches its tenth at v. 13. The eleven-man named unit reflects a military decimal structure (cf. the tribal warrior counts in chs. 7 and 12:23-37).</p>",
    "13": "<p>Jeremiah the tenth, Machbannai the eleventh. The complete Gadite officer list has eleven men. Verse 14&rsquo;s summary notes they ranged from commanders of a hundred to commanders of a thousand, showing these were mid-level officers, not common soldiers.</p>",
    "14": "<p><strong>min-bᵉnê-gāḏ rāʾšê haṣṣāḇāʾ</strong> — &lsquo;from the sons of Gad, commanders of the army.&rsquo; The superlative: <strong>haqqāṭōn lᵉmeʾāh wᵉhaggāḏôl laʾelep̄</strong> — &lsquo;the least over a hundred and the greatest over a thousand.&rsquo; This telescoping of magnitude is a rhetorical device emphasizing the quality of the entire contingent.</p>",
    "15": "<p><strong>hēmmāh ʿāḇrû ʾet-hayyardēn baḥōḏeš hārîʾšôn</strong> — &lsquo;they crossed the Jordan in the first month&rsquo; — during spring flooding (<em>kî mālaʾ ʿal kol-gᵉḏôtāyw</em> — &lsquo;when it had overflowed all its banks&rsquo;). Crossing a flood-stage Jordan to join David was an act of extraordinary commitment. The crossing motif echoes the Exodus/conquest Jordan-crossings as a theological parallel.</p>",
    "16": "<p><strong>wayyāḇōʾû min-bᵉnê binyāmîn wîhûḏāh</strong> — &lsquo;and there came from the sons of Benjamin and Judah to the stronghold.&rsquo; The double reference — Benjamin (Saul&rsquo;s tribe) and Judah (David&rsquo;s tribe) coming together — signals the beginning of the reunification that will culminate at Hebron.</p>",
    "17": "<p>David&rsquo;s interrogation of the arriving men: <strong>ʾim-lᵉšālôm bāʾtem ʾēlay lᵉʿāzᵉrēnî</strong> — &lsquo;if you have come to me in peace to help me.&rsquo; But if they have come to betray him to his enemies: <strong>yōkaḥ ʾĕlōhê ʾăḇôtênû</strong> — &lsquo;the God of our fathers will see and rebuke.&rsquo; David commends the judgment of betrayal to God rather than taking pre-emptive violence — showing the theological restraint that characterizes his fugitive period.</p>",
    "18": "<p><strong>wᵉrûaḥ lāḇᵉšāh ʾet-ʿămaśay</strong> — &lsquo;the Spirit clothed Amasai.&rsquo; The verb <em>lāḇaš</em> (to clothe) with Spirit-clothing is the same idiom used for Gideon (Judg 6:34) and Zechariah (2 Chr 24:20). The Spirit &lsquo;wearing&rsquo; a person rather than &lsquo;entering&rsquo; or &lsquo;coming upon&rsquo; them is distinctive. Amasai then speaks a poetic declaration: <strong>lᵉḵā dāwid wᵉʿimmᵉḵā ben-yišay šālôm šālôm lᵉḵā</strong> — &lsquo;Yours, David, and with you, son of Jesse! Peace, peace to you.&rsquo; The three-fold <em>šālôm</em> is a covenantal blessing formula.</p>",
    "19": "<p>Some Manassites defect to David as he goes with the Philistines to fight Saul (the battle of Jezreel/Gilboa context, 1 Sam 29). The Philistine lords dismissed David out of concern he might defect. <strong>bᵉḇôʾô ʿim-pᵉlištîm</strong> — &lsquo;when he came with the Philistines&rsquo; — the Chronicler does not explain the awkward context (David as Philistine vassal) but includes the result: Manassites joined him.</p>",
    "20": "<p>The Manassite defectors named: Adnah, Jozabad, Jediael, Michael, Jozabad (second), Elihu, Zillethai — &lsquo;heads of thousands&rsquo; (<em>rāʾšê hāʾălāpîm</em>) in Manasseh. These are senior military commanders changing allegiance from Saul to David, a major political shift.</p>",
    "21": "<p><strong>wᵉhēmmāh ʿāzᵉrû ʾet-dāwid ʿal-haggdûḏ</strong> — &lsquo;they helped David against the raiding band.&rsquo; The reference is to the Amalekite raid on Ziklag (1 Sam 30), where David recovered his people and plunder. <strong>kî gibbôrê ḥayil kull̄ām</strong> — &lsquo;for they were all mighty warriors.&rsquo;</p>",
    "22": "<p><strong>kî lᵉʿēt yôm bᵉyôm yāḇōʾû ʿal-dāwid lᵉʿāzᵉrô ʿaḏ-lᵉmaḥăneh gāḏôl kᵉmaḥănēh ʾĕlōhîm</strong> — &lsquo;for day by day they came to David to help him, until it was a great army like the army of God.&rsquo; The phrase <em>maḥănēh ʾĕlōhîm</em> (army/camp of God) appears elsewhere only in Gen 32:2 (Jacob&rsquo;s encounter with the angels). The Chronicler implicitly compares David&rsquo;s growing coalition to the divine army — a remarkable theological claim about the Davidic enterprise.</p>",
    "23": "<p><strong>wᵉʾēlleh misparê rāʾšê hāʾāḥûzāh lissᵉḇāʾ</strong> — &lsquo;and these are the numbers of the armed forces.&rsquo; <strong>bāʾû ʾel-dāwid ḥeḇrônāh lᵉhāsēb malḵût šāʾûl ʾēlāyw kᵉpî YHWH</strong> — &lsquo;to turn the kingdom of Saul to him according to the word of YHWH.&rsquo; This framing makes the Hebron anointing not a political event but the fulfillment of divine decree. The military census that follows (vv. 24-37) shows the scope of the all-Israel coalition.</p>",
    "24": "<p>Judah: 6,800 warriors bearing shield and spear. The relatively small number for Judah (compared to other tribes) may reflect that Judah had already been with David for years; the others are newly joining. The specific weapon groupings (<em>ṭōmᵉkê ṣinnāh wārōmaḥ</em> — shield-and-spear bearers) represent organized infantry units.</p>",
    "25": "<p>Simeon: 7,100 &lsquo;mighty men of valor for the war&rsquo; (<em>gibborê ḥayil laṣṣāḇāʾ</em>). Simeon was geographically integrated into Judah (Josh 19:1) and often acts as Judah&rsquo;s partner (Judg 1:3). Their substantial number shows strong tribal support.</p>",
    "26": "<p>Levi: 4,600. Levites are counted in a military list, which is unusual — they are normally exempt from warfare (Num 1:47-53). The Chronicler&rsquo;s inclusion of Levites in the Hebron coalition reflects his emphasis on priestly/cultic participation in establishing the Davidic order that will culminate in the temple.</p>",
    "27": "<p>The Aaronites specifically: Jehoiada the leader with 3,700 men. <strong>wᵉʿimmô yᵉhôyāḏāʿ hannāśîʾ lᵉʾahărōn</strong> — &lsquo;and with him Jehoiada, prince of the house of Aaron.&rsquo; Aaron&rsquo;s priestly house is thus explicitly part of the Davidic military coalition — the priestly and kingly orders are aligned from the beginning.</p>",
    "28": "<p><strong>wᵉṣādôq naʿar gibbôr ḥayil ûbêt ʾāḇîw śārîm ʿeśrîm ûšnayim</strong> — &lsquo;and Zadok, a young man mighty of valor, and his father&rsquo;s house: twenty-two commanders.&rsquo; This is the first mention of Zadok in Chronicles. His presence at David&rsquo;s anointing at Hebron anticipates his later appointment as chief priest (1 Chr 15:11; 2 Sam 8:17). The Chronicler introduces him here to show the Zadokite priesthood&rsquo;s foundation in the original Davidic covenant moment.</p>",
    "29": "<p>Benjamin: 3,000. But with a significant qualification: <strong>wᵉrōḇ mēhem ʿaḏ-hēnnāh šōmᵉrîm mišmeret bêt šāʾûl</strong> — &lsquo;for the majority of them had still been keeping watch over the house of Saul.&rsquo; The small number of Benjaminites reflects the complexity of the transition — Benjamin is Saul&rsquo;s tribe and many remained loyal to the Saulide house. The three thousand who came to David represent a significant but minority shift within the tribe.</p>",
    "30": "<p>Ephraim: 20,800, described as <strong>gibborê ḥayil anšê šēmōt lᵉbêt ʾăḇôtām</strong> — &lsquo;mighty men of valor, famous men in their fathers&rsquo; houses.&rsquo; The phrase <em>anšê šēmōt</em> (&lsquo;men of names/fame&rsquo;) is unusual — these are warriors of established reputation, not anonymous troops.</p>",
    "31": "<p>Half-tribe of Manasseh (west): 18,000, specifically named by name (<em>niqḇû bišmôt</em>) — a special notation suggesting these were individually identified in the administrative record. Their 18,000 represents substantial Manassite commitment to the Davidic transition.</p>",
    "32": "<p><strong>ûmibᵉnê yiśśāḵār yôḏᵉʿê bîn laʿittîm laḏaʿat mah-yāʿăśeh yiśrāʾēl</strong> — &lsquo;and from the sons of Issachar, those who understood the times, to know what Israel should do.&rsquo; This famous phrase (<em>yôḏᵉʿê bîn laʿittîm</em>) attributes to Issachar a quality of political-theological wisdom — understanding the &lsquo;times&rsquo; (<em>ʿittîm</em>) means discerning the moment when David&rsquo;s kingship was the proper order of things. <strong>kol-ʾăḥêhem ʿal-pîhem</strong> — &lsquo;and all their brothers were under their command&rsquo; — Issachar&rsquo;s wisdom leaders guide the whole tribe.</p>",
    "33": "<p>Zebulun: 50,000 warriors, specifically commended as <strong>lōʾ bᵉlēḇ wālēḇ</strong> — &lsquo;not of double heart&rsquo; (literally &lsquo;not with heart and heart&rsquo;). The double heart (<em>lēḇ wālēḇ</em>) signifies divided allegiance (cf. Ps 12:2). Zebulun&rsquo;s complete commitment is distinguished from Benjamin&rsquo;s divided loyalty (v. 29). The large number and the commendation make Zebulun the paradigm warrior-tribe at Hebron.</p>",
    "34": "<p>Naphtali: 1,000 commanders, 37,000 shield-and-spear warriors. The large base force with named commanders suggests Naphtali had a well-organized military structure. The north was strongly Davidic here.</p>",
    "35": "<p>Dan: 28,600 armed for war. Dan&rsquo;s territory was in the far north (following their migration in Judges 18), making their participation a statement of all-Israel support from the most geographically remote southern tribe&rsquo;s counterpart.</p>",
    "36": "<p>Asher: 40,000 warriors fit for war (<em>bᵉʿōrᵉkê milḥāmāh</em> — arranged/ordered for war). Asher, another northern coastal tribe, contributes substantially. The numbers mount as the list moves north, reaching a crescendo of pan-Israel military commitment.</p>",
    "37": "<p>Trans-Jordanian contingent: Reuben, Gad, and half-tribe of Manasseh (east): 120,000 with all manner of weapons of war (<em>kol-kᵉlê milḥāmāh</em>). This is the largest single block count. The trans-Jordanian tribes — geographically separated from the west by the Jordan — are fully committed. Their inclusion fulfills the geographic scope of the Davidic kingdom (&lsquo;all Israel&rsquo;).</p>",
    "38": "<p><strong>kol-ʾēlleh anšê milḥāmāh ʿōzrê maʿărāḵāh bᵉlēḇāḇ šālēm bāʾû ḥeḇrônāh lᵉhamlîḵ ʾet-dāwid</strong> — &lsquo;all these men of war, keeping ranks, came to Hebron with a whole heart to make David king over all Israel.&rsquo; The phrase <strong>lēḇāḇ šālēm</strong> (whole/undivided heart) is the Chronicler&rsquo;s signature expression for the proper covenantal posture (cf. 1 Chr 28:9; 29:19; 2 Chr 15:17; 16:9). <strong>wᵉgam kol-šᵉʾērît yiśrāʾēl lēḇ ʾeḥāḏ</strong> — &lsquo;and also all the rest of Israel was of one heart to make David king.&rsquo; The one-heart formula is the Chronicler&rsquo;s ideal of national unity.</p>",
    "39": "<p><strong>wayyihyû-šām ʿim-dāwid šᵉlōšet yāmîm ʾōḵlîm wᵉšōtîm</strong> — &lsquo;they were there with David three days, eating and drinking.&rsquo; The three-day covenant feast at Hebron echoes covenant meal patterns (Gen 31:54; Exod 24:11). Shared eating seals the covenant of kingship. The Chronicler&rsquo;s interest in communal celebration here anticipates the great liturgical celebrations of chs. 15-16 and Solomon&rsquo;s temple dedication.</p>",
    "40": "<p><strong>wᵉgam qᵉrôḇêhem ʿaḏ-yiśśāḵār wᵉzᵉḇûlun wᵉnaptālî mᵉḇîʾîm leḥem ʿal-ḥămōrîm</strong> — &lsquo;and also those nearest to them, as far as Issachar and Zebulun and Naphtali, brought bread on donkeys.&rsquo; The list of provisions — bread, figs, raisins, wine, oil, oxen, sheep — represents a banquet of all-Israel abundance. The provision-list functions as a symbol of national solidarity: every major food item is contributed, from grain products to livestock to wine. The feast is not just political but a covenant celebration in the fullest sense.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '1chronicles')
    merge_comm(existing, CHRON1)
    save_comm('mkt-original', '1chronicles', existing)
    print('1 Chronicles 11-12 mkt-original written.')

if __name__ == '__main__':
    main()
